import React, { useState } from 'react';
import Layout from '../components/Layout';
import { ArrowLeft, Plus, Save, Upload } from 'lucide-react';
import { Link } from 'react-router-dom';

const CreateScenario: React.FC = () => {
  const [scenario, setScenario] = useState({
    title: '',
    description: '',
    category: 'Criminal Law',
    difficulty: 'Beginner',
    duration: '30',
    participants: 2,
    pointsRequired: 1000,
    monthlyLimit: 5
  });

  const [sections, setSections] = useState([
    {
      id: 1,
      title: 'Opening Statements',
      content: '',
      timeLimit: 10
    }
  ]);

  const categories = ['Criminal Law', 'Civil Law', 'Corporate Law', 'Family Law', 'Constitutional Law', 'Tax Law', 'Intellectual Property'];
  const difficulties = ['Beginner', 'Intermediate', 'Advanced', 'Expert'];

  const handleScenarioChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setScenario(prev => ({
      ...prev,
      [name]: name === 'duration' || name === 'participants' || name === 'pointsRequired' || name === 'monthlyLimit' 
        ? parseInt(value) || 0 
        : value
    }));
  };

  const handleSectionChange = (id: number, field: string, value: string) => {
    setSections(prev => 
      prev.map(section => 
        section.id === id 
          ? { ...section, [field]: field === 'timeLimit' ? parseInt(value) || 0 : value } 
          : section
      )
    );
  };

  const addSection = () => {
    setSections(prev => [
      ...prev,
      {
        id: prev.length + 1,
        title: '',
        content: '',
        timeLimit: 10
      }
    ]);
  };

  const removeSection = (id: number) => {
    if (sections.length > 1) {
      setSections(prev => prev.filter(section => section.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // In a real app, this would send the data to a backend
    console.log('Scenario submitted:', { scenario, sections });
    alert('Scenario created successfully! In a real application, this would be saved to your account.');
  };

  return (
    <Layout>
      <div className="container mx-auto px-4 py-8">
        <div className="mb-6">
          <Link to="/marketplace" className="flex items-center text-indigo-600 hover:text-indigo-800 transition duration-300">
            <ArrowLeft className="w-5 h-5 mr-2" />
            Back to Marketplace
          </Link>
        </div>

        <div className="bg-white rounded-xl shadow-sm p-6 mb-8">
          <div className="text-center mb-8">
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Create Your Own Case Scenario</h1>
            <p className="text-gray-600">
              Design custom legal scenarios to practice specific skills or situations
            </p>
          </div>

          <div className="bg-gradient-to-r from-indigo-50 to-purple-50 rounded-lg p-6 mb-8 border border-indigo-100">
            <div className="flex flex-col md:flex-row items-center justify-between">
              <div className="mb-4 md:mb-0">
                <h2 className="text-xl font-bold text-gray-900 mb-2">Premium Feature</h2>
                <p className="text-gray-700">
                  Create up to 5 custom scenarios per month for just <span className="font-bold text-indigo-600">1000 points</span>
                </p>
              </div>
              <div className="bg-white rounded-lg p-4 shadow-sm">
                <div className="text-center">
                  <div className="text-2xl font-bold text-indigo-600">1000</div>
                  <div className="text-sm text-gray-600">points</div>
                  <div className="text-xs text-gray-500">5 scenarios/month</div>
                </div>
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit}>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Scenario Title</label>
                <input
                  type="text"
                  name="title"
                  value={scenario.title}
                  onChange={handleScenarioChange}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                  placeholder="e.g., Cross-Examination of Expert Witness"
                  required
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Category</label>
                <select
                  name="category"
                  value={scenario.category}
                  onChange={handleScenarioChange}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                >
                  {categories.map(category => (
                    <option key={category} value={category}>{category}</option>
                  ))}
                </select>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Difficulty</label>
                <select
                  name="difficulty"
                  value={scenario.difficulty}
                  onChange={handleScenarioChange}
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                >
                  {difficulties.map(difficulty => (
                    <option key={difficulty} value={difficulty}>{difficulty}</option>
                  ))}
                </select>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Estimated Duration (minutes)</label>
                <input
                  type="number"
                  name="duration"
                  value={scenario.duration}
                  onChange={handleScenarioChange}
                  min="5"
                  max="180"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                  required
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Participants</label>
                <input
                  type="number"
                  name="participants"
                  value={scenario.participants}
                  onChange={handleScenarioChange}
                  min="1"
                  max="20"
                  className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                  required
                />
              </div>
            </div>
            
            <div className="mb-8">
              <label className="block text-sm font-medium text-gray-700 mb-2">Description</label>
              <textarea
                name="description"
                value={scenario.description}
                onChange={handleScenarioChange}
                rows={4}
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                placeholder="Describe the legal scenario, key issues, and learning objectives..."
                required
              />
            </div>
            
            <div className="mb-8">
              <div className="flex justify-between items-center mb-4">
                <h2 className="text-xl font-bold text-gray-900">Scenario Sections</h2>
                <button
                  type="button"
                  onClick={addSection}
                  className="flex items-center bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300"
                >
                  <Plus className="w-4 h-4 mr-2" />
                  Add Section
                </button>
              </div>
              
              <div className="space-y-6">
                {sections.map((section, index) => (
                  <div key={section.id} className="border border-gray-200 rounded-lg p-6">
                    <div className="flex justify-between items-center mb-4">
                      <h3 className="text-lg font-medium text-gray-900">Section {index + 1}</h3>
                      {sections.length > 1 && (
                        <button
                          type="button"
                          onClick={() => removeSection(section.id)}
                          className="text-red-600 hover:text-red-800 transition duration-300"
                        >
                          Remove
                        </button>
                      )}
                    </div>
                    
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">Section Title</label>
                        <input
                          type="text"
                          value={section.title}
                          onChange={(e) => handleSectionChange(section.id, 'title', e.target.value)}
                          className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                          placeholder="e.g., Opening Statements"
                          required
                        />
                      </div>
                      
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">Time Limit (minutes)</label>
                        <input
                          type="number"
                          value={section.timeLimit}
                          onChange={(e) => handleSectionChange(section.id, 'timeLimit', e.target.value)}
                          min="1"
                          max="60"
                          className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                          required
                        />
                      </div>
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">Content</label>
                      <textarea
                        value={section.content}
                        onChange={(e) => handleSectionChange(section.id, 'content', e.target.value)}
                        rows={3}
                        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                        placeholder="Describe what happens in this section, key points to cover, etc."
                        required
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>
            
            <div className="flex justify-end">
              <button
                type="submit"
                className="flex items-center bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-6 py-3 rounded-lg hover:from-indigo-700 hover:to-purple-700 transition duration-300 font-medium"
              >
                <Save className="w-5 h-5 mr-2" />
                Create Scenario
              </button>
            </div>
          </form>
        </div>
      </div>
    </Layout>
  );
};

export default CreateScenario;
